var e=JSON.parse(`[{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"모네! 모네네네!!","JPN":"モネ！　モネネネ！！","ENG":"Mone! Monenene!","TWN":"莫妮！莫妮妮妮！！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이제 어떡해요, 실장님? 수가 줄기는커녕 점점 늘어나고 있잖아요!","JPN":"どうしますか、室長？　数が減るどころか、どんどん増えてるじゃないですか！","ENG":"What do we do now, Chief? They're multiplying!","TWN":"現在怎麼辦，室長？數量不僅沒有減少，反而還越來越多！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이상해. 펭귄 친구들은 다들 착하단 말이야.","JPN":"おかしいね。ペンギンちゃんたちはみんないい子なのに。","ENG":"That's strange. The penguins are all nice.","TWN":"奇怪。企鵝朋友們都很善良的。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이렇게까지 화낼 리가 없는데?","JPN":"ここまで怒るはずないんだけど？","ENG":"I don't know why they're so angry.","TWN":"不至於這麼生氣吧？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네네네!","JPN":"モネ！　モネネネ！","ENG":"Mone! Monenene!","TWN":"莫妮！莫妮妮妮！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"싫습니다. 이건 크레데레가 정당한 값을 지불하고 얻은 거예요.","JPN":"イヤです。これはクレデレが正当な対価を支払って得たものです。","ENG":"No. Credere acquired these by legitimate means.","TWN":"不行，這是克蕾妲莉花錢買來的。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"돌려받고 싶다면 세 배를 지불하세요, 현실은 녹록치 않은 법입니다.","JPN":"返してほしいのなら、3倍出しなさい。現実はそう甘くないのです。","ENG":"Pay triple the price if you want these back. Reality is harsh, so you will have to deal with it.","TWN":"如果想要拿回去，就付三倍的價錢吧，現實是很殘酷的。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아직도 실랑이 중이잖아! 그 정도면 좀 양보하라고요!","JPN":"まだ揉めてる！　そのくらいで譲ってやりなさいよ！","ENG":"She's still trying to rip them off! Oh, come on! Just give up already!","TWN":"還在爭嗎！都這樣了你就讓個步吧！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"싫어요. 남은 용돈을 탈탈 털어 준비한 회심의 사업이란 말입니다.","JPN":"イヤです。少ないお小遣いをかき集めて準備した会心の事業なんですよ。","ENG":"No. Credere used up all her remaining allowance to start this business.","TWN":"不行。這可是克蕾妲莉把剩下的零用錢全部掏出來，打算做一個穩賺不賠的生意的。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"혹여 이분들의 법적 소유주가 있어 재물손괴죄가 성립되는 건 아닌지 조사했어요.","JPN":"もしも、この方々に法的持ち主がいて器物損壊罪が成立するのではないかと調査しました。","ENG":"Credere had to investigate whether or not they had a legal owner to make her guilty of theft.","TWN":"克蕾妲莉怕犯下財物損毀罪，還特地調查過原本是否有合法所有人……"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"합법입니다. 꼬우면 돈 가져오세요.","JPN":"合法です。気に入らなかったらお金を持ってきなさい。","ENG":"And Credere is not doing anything illegal. So, bring Credere money if you want these.","TWN":"結果，克蕾妲莉是合法的，不服的話就拿錢來吧。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"어라.","JPN":"あれ。","ENG":"Huh?","TWN":"哎呀。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"엣취.","JPN":"くしゅん。","ENG":"Ah-choo!","TWN":"哈啾。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"자요. 코 좀 푸세요.","JPN":"はい。鼻かんでください。","ENG":"Here. Blow your nose.","TWN":"給你，把鼻涕擤一擤吧。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"크레데레는 콧물 같은 거 안 흘립니다, 훌쩍.","JPN":"クレデレは鼻水なんて流しません、スンッ。","ENG":"Credere never has a runny nose. *Sniffle*","TWN":"克蕾妲莉不會流鼻涕的，吸吸。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네? 모네네?","JPN":"モネ？　モネネ？","ENG":"Mone? Monene?","TWN":"莫妮？莫妮妮？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네! 모네네네!","JPN":"モネネ！　モネネネ！","ENG":"Monene! Monenene!","TWN":"莫妮妮！莫妮妮妮！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"다행이다. 유피가 과자를 줘서 펭귄들도 화가 풀렸나 봐.","JPN":"よかった。ユピがお菓子をあげて、ペンギンも怒りが収まったみたい。","ENG":"That's a relief. Seems like the penguins are happy with the snacks you gave them.","TWN":"太好了。幸虧有悠菲的點心，企鵝們好像消氣了。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나름 자신작이거든요. 누구 고집 탓에 전부 꼬일 뻔했지만.","JPN":"これ自信作なんです。誰かさんの我がままのせいで、全部ダメになるところでしたけど。","ENG":"I'm pretty confident with them. A certain somebody's stubbornness almost ruined the whole thing, though.","TWN":"這是我的得意之作。雖然差點因為某人的固執全賠進去了。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"옷도 잘 입고 다니시는 분이 뭐가 아쉬워서 펭귄들 상대로 횡포를 부리던 거예요?","JPN":"立派な服を着てる方が、どうしてペンギン相手に横暴な振る舞いをしてたんですか？","ENG":"You don't seem like you need money. Why were you trying to take advantage of the penguins?","TWN":"你看起來也不像缺錢的人，為什麼要對企鵝們做這種事？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"아빠가, 훌쩍. 독립하고 싶으면 뭐라도 해보라고, 훌쩍.","JPN":"お父さんが、スンッ。独立したいならなんでもやってみろって、スンッ。","ENG":"Dad. *Sniffle* He told me to do something if Credere wanted to move out. *Sniffle*","TWN":"爸爸說，吸吸。如果想要獨立，就去做點什麼，吸吸。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"그렇게 된 겁니다.","JPN":"それでこうなったわけです。","ENG":"So, that's what happened.","TWN":"……事情就是這樣。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 하나도 모르겠어요. 이상한 짓 말고 얌전히 집에나 가세요.","JPN":"まったく、なんのことだが。変なことしてないで、大人しく家に帰ってください。","ENG":"Right. I didn't understand any of that. Don't do anything reckless and just go home.","TWN":"是是是。我完全不明白。小孩子就別做奇怪的事，乖乖回家去吧。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};